package com.jyfq.loan.thirdparty.model;

import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.math.BigDecimal;
import java.util.List;
import java.util.Map;

/**
 * Pre-check result.
 */
@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class PreCheckResult {

    /** Whether the pre-check passed. */
    private boolean pass;

    /** Real-time price / settlement price. */
    private BigDecimal price;

    /** Third-party request id / uuid. */
    private String uuid;

    /** Third-party order id. */
    private String orderId;

    /** Downstream product logo. */
    private String productLogo;

    /** Downstream product name. */
    private String productName;

    /** Downstream company name. */
    private String companyName;

    /** Downstream protocol list. */
    private List<Map<String, Object>> protocolList;

    /** Product id. */
    private Long productId;

    /** Institution id. */
    private Long instId;

    /** Institution code. */
    private String instCode;

    /** Local order number generated by this system. */
    private String localOrderNo;

    /** Reject reason when not passed. */
    private String rejectReason;
}
